import{_ as t,o as e,c as i,a3 as o}from"./chunks/framework.d0TBG0Rg.js";const m=JSON.parse('{"title":"如何使用 Mizuki Bot","description":"介绍如何将 Mizuki Bot 邀请加入 QQ 群并开始使用，包括加入官方交流群指引、Bot 拉取流程及指令触发基本规范。","frontmatter":{"title":"如何使用 Mizuki Bot","description":"介绍如何将 Mizuki Bot 邀请加入 QQ 群并开始使用，包括加入官方交流群指引、Bot 拉取流程及指令触发基本规范。"},"headers":[],"relativePath":"usage.md","filePath":"usage.md"}'),r={name:"usage.md"};function s(c,a,d,n,l,u){return e(),i("div",null,[...a[0]||(a[0]=[o('<h1 id="如何使用-mizuki-bot" tabindex="-1">如何使用 Mizuki Bot <a class="header-anchor" href="#如何使用-mizuki-bot" aria-label="Permalink to &quot;如何使用 Mizuki Bot&quot;">​</a></h1><blockquote><p>欢迎使用 Mizuki Bot！在这里您可以快速了解如何将 Bot 邀请至您的群组并开始使用。</p></blockquote><br><div class="mzk-card mzk-card--blue"><h3>1. 加入交流群</h3><p> 在开始使用前，建议您先加入我们的官方用户交流群，以获取最新的 Bot 动态、使用指导以及及时的 Bug 反馈支持。 </p><p style="font-weight:bold;"> 官方交流群：<a href="https://qun.qq.com/universal-share/share?ac=1&amp;authKey=sZzYueQrNCiaA55yoYVJ2%2BqgW3iCEo5t2OwRFNaWkbh5z1kZYbTt1ZufA1DXODSP&amp;busi_data=eyJncm91cENvZGUiOiIxMDUzOTY0NDMxIiwidG9rZW4iOiJZYkRneTFGR1dTY2NWVFpTcHVKVGFzRUs4T1BJaVVGUzE1bUFybS9nL3psQ044YS9PY1Z6aE5kT2cwcTBxcEpaIiwidWluIjoiMjMzODY4MDE0OCJ9&amp;data=PHQXSsjB5M1bHiDjdzUMazkBeM4ZFkFRmmmvVA7EmJn8yFUJRUyHMZ1aT9NzSny0GPN8rkwUQ5aAWSn8L-aL_w&amp;svctype=4&amp;tempid=h5_group_info" target="_blank" style="color:var(--vp-c-brand-1);text-decoration:underline;">国 立 中 央 大 学 政 教 处 音 游 组 (1053964431)</a></p></div><div class="mzk-card mzk-card--green"><h3>2. 邀请 Bot 入群</h3><ul><li>使用 Bot QQ 号 <code>3889004352</code>（Amia_晓山瑞希）邀请入群即可。</li><li>在拟添加的群聊中选择“从群聊中选择联系人”将其拉入。</li><li><strong>注意：</strong> 为了保证账户安全性，所有用户在拉取 Bot 前都需要进入上方交流群，以免封禁消息通知不及时。</li></ul></div><div class="mzk-card mzk-card--orange"><h3>3. 触发指令</h3><p> 入群后，您可以直接发送功能指令（如 <code>帮助</code>、<code>个人信息</code> 等）来触发 Bot。 </p><div class="mzk-alert"><strong>温馨提示：</strong> 触发请直接发送指令文本，严禁 @机器人。 </div></div>',6)])])}const k=t(r,[["render",s]]);export{m as __pageData,k as default};
